import{c as a,Q as i,j as t,m as s}from"./chunks/framework.DVkeSyfh.js";const m=JSON.parse('{"title":"Ideas","description":"","frontmatter":{},"headers":[],"relativePath":"ideas.md","filePath":"ideas.md","lastUpdated":1781921330000}'),r={name:"ideas.md"};function l(o,e,d,c,n,u){return i(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="ideas" tabindex="-1">Ideas <a class="header-anchor" href="#ideas" aria-label="Permalink to &quot;Ideas&quot;">​</a></h1><p>This page captures larger workflow ideas that are not implemented yet. Treat them as product notes, not as current behavior or API contracts.</p><h2 id="smart-set-builder-from-seed-tracks" tabindex="-1">Smart Set Builder From Seed Tracks <a class="header-anchor" href="#smart-set-builder-from-seed-tracks" aria-label="Permalink to &quot;Smart Set Builder From Seed Tracks&quot;">​</a></h2><p>Add a dedicated UI workflow that generates a varied DJ set candidate list from 3-10 selected seed tracks. The goal is not just &quot;more similar tracks&quot;; it should act as a curator over existing analysis models and produce a useful sequence for listening, digging, or set preparation.</p><p>The first version could work without training a new model:</p><ul><li>use MERT similarity for musical/audio closeness;</li><li>use MAEST labels for genre and texture hints;</li><li>use SONARA features for BPM, energy, and rhythmic compatibility;</li><li>use promoted classifier scores such as <code>abstract_edge</code>, <code>break_energy</code>, or <code>voice_presence</code> as preference and exclusion signals;</li><li>exclude tracks that are already labelled, liked, reviewed, or recently shown when the user wants discovery rather than confirmation.</li></ul><p>Suggested modes:</p><ul><li><code>similar_crate</code>: stay close to the seed tracks and rank by strong agreement across MERT, MAEST, SONARA, and classifier scores.</li><li><code>weird_adjacent</code>: keep enough similarity to remain relevant, but prefer candidates with unusual classifier/model disagreement or more experimental texture.</li><li><code>balanced_set</code>: generate a DJ-oriented list with bridge tracks, BPM/energy compatibility, and reduced repetition between adjacent tracks.</li><li><code>discovery</code>: allow riskier candidates and reserve part of the list for low-confidence tracks that could reveal useful new classifier positives.</li></ul><p>Useful controls:</p><ul><li>seed track picker;</li><li>target length;</li><li>diversity amount;</li><li>energy curve such as warmup, balanced, peak, or wave;</li><li>classifier targets and avoid rules;</li><li>exclude liked, labelled, reviewed, or already exported tracks;</li><li>optional BPM/key compatibility constraints.</li></ul><p>The generated result should explain why each track was selected, for example <code>similar_to_seed</code>, <code>bridge</code>, <code>weird_adjacent</code>, or <code>classifier_match</code>, and expose the underlying MERT/MAEST/SONARA/classifier scores for manual review.</p><p>Possible API shape:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>POST /api/set-builder/generate</span></span></code></pre></div><p>Input fields:</p><ul><li><code>seed_track_ids</code></li><li><code>limit</code></li><li><code>mode</code></li><li><code>diversity</code></li><li><code>energy_curve</code></li><li><code>classifier_targets</code></li><li><code>exclude_reviewed</code></li></ul><p>Output fields:</p><ul><li>ranked track rows;</li><li>selection reason;</li><li>similarity and diversity scores;</li><li>relevant classifier scores;</li><li>optional set-order metadata such as energy step or bridge target.</li></ul><p>Later extensions could send selected tracks to Rhythm Lab, mark them as reviewed, export M3U/XLSX lists, or save generated sessions for iterative active-learning loops.</p>',18)])])}const h=a(r,[["render",l]]);export{m as __pageData,h as default};
